SELECT AVG(wickets) AS average_wickets
FROM bowling_stats
WHERE match_id = 123;

SELECT AVG(total_runs_per_match) AS average_runs_per_match
FROM (
    SELECT match_id, SUM(runs_scored) AS total_runs_per_match
    FROM innings
    GROUP BY match_id
) AS match_runs;

SELECT SUM(runs_scored) AS total_runs
FROM player_match_stats
WHERE match_id = 123;

SELECT STRFTIME('%Y', match_date) AS year, COUNT(match_id) AS total_matches
FROM matches
GROUP BY year;

SELECT COUNT(match_id) AS total_matches_played
FROM matches
WHERE team1 = 'India' OR team2 = 'India';

SELECT AVG(balls_bowled) AS average_deliveries
FROM bowling_stats
WHERE match_id = 101;
